<?php
namespace App\Domain\Equipment;
use App\Domain\Equipment\Data\ItemStatBonuses;use App\Domain\Inventory\ItemClassification;use App\Domain\WorldCatalog\ItemType;use App\Models\Item;use InvalidArgumentException;
final class ItemStatBonusValidator{private $classification;public function __construct(ItemClassification $classification){$this->classification=$classification;}public function bonuses(Item $item){$values=[$item->max_health_bonus,$item->attack_bonus,$item->defense_bonus,$item->accuracy_bonus,$item->evasion_bonus,$item->critical_chance_bonus,$item->attack_speed_bonus];$values=array_map(function($value){return$value===null?0:$value;},$values);foreach($values as $value)if(!is_numeric($value)||(float)$value<0)throw new InvalidArgumentException('Item stat bonuses must be non-negative.');$bonuses=new ItemStatBonuses($values[0],$values[1],$values[2],$values[3],$values[4],$values[5],$values[6]);if($bonuses->hasAny()&&($item->item_type!==ItemType::EQUIPMENT||$item->equipment_type===null||$this->classification->classify($item)!==ItemClassification::UNIQUE))throw new InvalidArgumentException('Item stat bonuses require a coherent equippable Item.');return$bonuses;}}
